      "content": "const problemsData = require('../../data/problems.json');

class ProblemsService {
  static getProblemById(problemId) {
    const problem = problemsData.find(p => p.id === problemId);
    if (!problem) {
      return null;
    }

    // Aggregate component statistics
    const components = problem.components || [];
    const languageCounts = {};
    const statusCounts = {};
    let maxPoints = 0;

    components.forEach(component => {
      // Count languages
      if (component.language) {
        languageCounts[component.language] = (languageCounts[component.language] || 0) + 1;
      }

      // Count statuses
      if (component.status) {
        statusCounts[component.status] = (statusCounts[component.status] || 0) + 1;
      }

      // Track max points
      if (typeof component.points === 'number' && component.points > maxPoints) {
        maxPoints = component.points;
      }
    });

    return {
      ...problem,
      componentStats: {
        languageCounts,
        statusCounts,
        maxPoints
      }
    };
  }
}

module.exports = ProblemsService;
